package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PrestatieSamenvatting;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.Dienstverband;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.Collection;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.INH_WERKUITKERING_UREN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.INHOUDINGEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONCODE_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PRESTATIE_SAMENVATTING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.AANTAL_UREN_EFFECTIEF_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.AANTAL_UREN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.BASIS_BEDRAG_WERKUITKERING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.MAATMAN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.TEWERKSTELLING_PERIODE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenNettoKey.NETTO_KEY;

public class BerekenWerkuitkeringInhoudingen extends AbstractRekenCommand {

    private static final LocalDate BEGIN_WERKUITKERING = new LocalDate(2010, 4, 1);

    public BerekenWerkuitkeringInhoudingen(NlpGlobalService globalService) {
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        WerkuitkeringGegevens gegevens = analyseWerkuitkering(mainContext);
        if (gegevens.werkuitkeringAke != null) {
            berekenWerkuitkering(mainContext, gegevens);
        }
        return CONTINUE_PROCESSING;
    }

    private static class WerkuitkeringGegevens {

        private AardKodeExtensie werkuitkeringAke = null;
        private Money basisBedrag = null;
        private BigDecimal maatman = null;
        private List<Opdracht> teBeschouwen = new ArrayList<>();
        private Map<Opdracht, Opper> opdrachtToOpper = new HashMap<>();
        private LocalDateInterval tewerkstellingPeriode = null;
    }

    private WerkuitkeringGegevens analyseWerkuitkering(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        RegulManager regulManager = mainContext.getUnchecked(REGUL_MANAGER_KEY);
        LoonCodeManager loonCodeManager = mainContext.getUnchecked(LOONCODE_MANAGER_KEY);
        WerkuitkeringGegevens gegevens = new WerkuitkeringGegevens();
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            int aantalGevonden = 0;
            for (Opper opper : opdracht.getOpperSlices()) {
                List<NlpPrestatie> inhoudingen = opdrachtContext.getDoubleKey(INHOUDINGEN_KEY, opper);
                for (NlpPrestatie inhouding : inhoudingen) {
                    AardKodeExtensie aardKodeExtensie = loonCodeManager.getByPrestatie(inhouding);
                    if (aardKodeExtensie.behoortTotGroep(INH_WERKUITKERING_UREN_KEY)) {
                        aantalGevonden++;
                        if (checkVoorRegul(aantalGevonden, opper, inhouding, aardKodeExtensie, gegevens)) {
                            regulManager.doRegulException(opdracht, Regulkode.WERKUITKERING_BASISBEDRAG);
                        } else if (gegevens.werkuitkeringAke == null) {
                            gegevens.werkuitkeringAke = aardKodeExtensie;
                            gegevens.basisBedrag = inhouding.getY();
                            gegevens.maatman = opper.getRszppo().getMaatman();
                        }
                        gegevens.opdrachtToOpper.put(opdracht, opper);
                        gegevens.teBeschouwen.add(opdracht);
                    }
                }
            }
        }
        if (gegevens.werkuitkeringAke != null && rekenTijd.beginDatum.isBefore(BEGIN_WERKUITKERING)) {
            regulManager.doRegulException(gegevens.teBeschouwen.get(0), Regulkode.WERKUITKERING_ONGELDIGE_PERIODE);
        }

        gegevens.tewerkstellingPeriode = bepaalTewerkstellingPeriode(gegevens.teBeschouwen, rekenTijd);
        return gegevens;
    }

    private boolean checkVoorRegul(
            int aantalGevonden, Opper opper, NlpPrestatie inhouding, AardKodeExtensie aardKodeExtensie,
            WerkuitkeringGegevens gegevens) {
        boolean check = inhouding.getX().compareTo(BigDecimal.ONE) != 0 || aantalGevonden > 1;
        if (!check && gegevens.werkuitkeringAke != null) {
            check = !(gegevens.werkuitkeringAke.equals(aardKodeExtensie) && gegevens.basisBedrag.equals(inhouding.getY()))
                    || gegevens.maatman.compareTo(opper.getRszppo().getMaatman()) != 0;
        }
        return check;
    }

    private LocalDateInterval bepaalTewerkstellingPeriode(List<Opdracht> opdrachten, RekenTijd rekenTijd) {
        LocalDateInterval tewerkstellingPeriode = null;
        for (Opdracht opdracht : opdrachten) {
            for (Opper opper : opdracht.getOpperSlices()) {
                if (opper.getRszppo().getDienstverband() == Dienstverband.JA) {
                    if (tewerkstellingPeriode == null) {
                        tewerkstellingPeriode = opper.getActualInterval().overlap(rekenTijd.rekenPeriode);
                    } else {
                        LocalDateInterval temp = opper.getActualInterval().overlap(rekenTijd.rekenPeriode);
                        LocalDate twBegin = tewerkstellingPeriode.getStart();
                        if (temp.getStart().compareTo(twBegin) < 0) {
                            twBegin = temp.getStart();
                        }
                        LocalDate twEinde = tewerkstellingPeriode.getEnd();
                        if (temp.getEnd().compareTo(twEinde) > 0) {
                            twEinde = temp.getEnd();
                        }
                        tewerkstellingPeriode = new LocalDateInterval(twBegin, twEinde);
                    }
                }
            }
        }
        return tewerkstellingPeriode;
    }

    private static final BigDecimal UREN_WEEK_NAAR_MAAND_BENADERING = BigDecimal.valueOf(4);

    private void berekenWerkuitkering(RekenContext mainContext, WerkuitkeringGegevens gegevens) {
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        MoneyMap<Opdracht> opdrachtToNetto = new HashMoneyMap<>();
        Map<Opdracht, BigDecimal> opdrachtToUren = new HashMap<>();
        Money totaalNetto = Money.ZERO;
        BigDecimal urenTotaal = BigDecimal.ZERO;
        for (Opdracht opdracht : gegevens.teBeschouwen) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            Collection<LoonElement> elementen = manager.getOpdrachtsElementen(opdracht);
            Money netto = Money.ZERO;
            for (LoonElement element : elementen) {
                if (!element.getAardKodeExtensie().getAard().equals(AardKodeExt.I_KODE_EXT.getCode())) {
                    netto = netto.add(element.getPropertyMoney(NETTO_KEY));
                }
            }
            totaalNetto = totaalNetto.add(netto);
            opdrachtToNetto.put(opdracht, netto);
            BigDecimal uren = BigDecimal.ZERO;
            for (Opper opper : opdracht.getOpperSlices()) {
                PrestatieSamenvatting samenvatting = opdrachtContext.getDoubleKey(PRESTATIE_SAMENVATTING_KEY, opper);
                uren = uren.add(samenvatting.getWerkuitkeringUren());
            }
            urenTotaal = urenTotaal.add(uren);
            opdrachtToUren.put(opdracht, uren);
        }
        BigDecimal maatmanMaand = gegevens.maatman.multiply(UREN_WEEK_NAAR_MAAND_BENADERING);
        BigDecimal urenEffectief = urenTotaal.min(maatmanMaand);

        Money inhoudingBedrag = gegevens.basisBedrag.multiply(urenEffectief).divide(maatmanMaand).round(2);
        inhoudingBedrag = inhoudingBedrag.min(totaalNetto).max(Money.ZERO);

        Money carryover = Money.ZERO;
        for (Opdracht opdracht : gegevens.teBeschouwen) {
            Opper opper = gegevens.opdrachtToOpper.get(opdracht);

            LoonElement element = new LoonElement(gegevens.werkuitkeringAke);
            manager.addLoonElement(element, opper);
            Money netto = opdrachtToNetto.getMoney(opdracht);
            if (netto.signum() != 0) {
                Money elementBedrag = inhoudingBedrag.multiply(netto.divide(totaalNetto)).add(carryover);
                carryover = elementBedrag.subtract(elementBedrag.round(2));
                elementBedrag = elementBedrag.round(2);
                element.putProperty(NETTO_KEY, elementBedrag.negate());
                element.putProperty(BASIS_BEDRAG_WERKUITKERING_KEY, gegevens.basisBedrag);
                element.putProperty(TEWERKSTELLING_PERIODE_KEY, gegevens.tewerkstellingPeriode);
                element.putProperty(AANTAL_UREN_KEY, urenTotaal);
                element.putProperty(AANTAL_UREN_EFFECTIEF_KEY, urenEffectief);
                element.putProperty(MAATMAN_KEY, gegevens.maatman);
            }
        }
    }

}
